INSERT INTO public.questions (skill_id, level, question_text, question_type, options, correct_answer, marks) VALUES
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which keyword is used to define a class in Java?', 'mcq', '[{"text":"class","is_correct":true},{"text":"struct","is_correct":false},{"text":"define","is_correct":false},{"text":"object","is_correct":false}]', 'class', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is the default value of an int variable in Java?', 'mcq', '[{"text":"0","is_correct":true},{"text":"null","is_correct":false},{"text":"1","is_correct":false},{"text":"undefined","is_correct":false}]', '0', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which method is the entry point of a Java program?', 'mcq', '[{"text":"main()","is_correct":true},{"text":"start()","is_correct":false},{"text":"run()","is_correct":false},{"text":"init()","is_correct":false}]', 'main()', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which of the following is not a primitive data type in Java?', 'mcq', '[{"text":"String","is_correct":true},{"text":"int","is_correct":false},{"text":"boolean","is_correct":false},{"text":"char","is_correct":false}]', 'String', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What does JVM stand for?', 'mcq', '[{"text":"Java Virtual Machine","is_correct":true},{"text":"Java Variable Method","is_correct":false},{"text":"Java Verified Machine","is_correct":false},{"text":"Java Visual Method","is_correct":false}]', 'Java Virtual Machine', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which operator is used for string concatenation?', 'mcq', '[{"text":"+","is_correct":true},{"text":"&","is_correct":false},{"text":".","is_correct":false},{"text":",","is_correct":false}]', '+', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is the size of int in Java?', 'mcq', '[{"text":"4 bytes","is_correct":true},{"text":"2 bytes","is_correct":false},{"text":"8 bytes","is_correct":false},{"text":"1 byte","is_correct":false}]', '4 bytes', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which keyword prevents a class from being inherited?', 'mcq', '[{"text":"final","is_correct":true},{"text":"static","is_correct":false},{"text":"private","is_correct":false},{"text":"abstract","is_correct":false}]', 'final', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is the parent class of all Java classes?', 'mcq', '[{"text":"Object","is_correct":true},{"text":"Class","is_correct":false},{"text":"Main","is_correct":false},{"text":"Base","is_correct":false}]', 'Object', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which keyword is used to create an object?', 'mcq', '[{"text":"new","is_correct":true},{"text":"create","is_correct":false},{"text":"make","is_correct":false},{"text":"init","is_correct":false}]', 'new', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which access modifier makes a member accessible only within the same class?', 'mcq', '[{"text":"private","is_correct":true},{"text":"public","is_correct":false},{"text":"protected","is_correct":false},{"text":"default","is_correct":false}]', 'private', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is method overloading?', 'mcq', '[{"text":"Same method name with different parameters","is_correct":true},{"text":"Overriding parent methods","is_correct":false},{"text":"Creating abstract methods","is_correct":false},{"text":"Using static methods","is_correct":false}]', 'Same method name with different parameters', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which collection class allows duplicate elements?', 'mcq', '[{"text":"ArrayList","is_correct":true},{"text":"HashSet","is_correct":false},{"text":"TreeSet","is_correct":false},{"text":"HashMap","is_correct":false}]', 'ArrayList', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What does the static keyword mean in Java?', 'mcq', '[{"text":"Belongs to the class, not instance","is_correct":true},{"text":"Cannot be changed","is_correct":false},{"text":"Accessible everywhere","is_correct":false},{"text":"Runs at startup","is_correct":false}]', 'Belongs to the class, not instance', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which interface must be implemented for sorting?', 'mcq', '[{"text":"Comparable","is_correct":true},{"text":"Serializable","is_correct":false},{"text":"Runnable","is_correct":false},{"text":"Iterable","is_correct":false}]', 'Comparable', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is the purpose of this keyword?', 'mcq', '[{"text":"Refers to current object","is_correct":true},{"text":"Refers to parent class","is_correct":false},{"text":"Creates new object","is_correct":false},{"text":"Imports a class","is_correct":false}]', 'Refers to current object', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which exception is thrown when array index is out of bounds?', 'mcq', '[{"text":"ArrayIndexOutOfBoundsException","is_correct":true},{"text":"NullPointerException","is_correct":false},{"text":"ClassCastException","is_correct":false},{"text":"ArithmeticException","is_correct":false}]', 'ArrayIndexOutOfBoundsException', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is encapsulation?', 'mcq', '[{"text":"Wrapping data and methods together","is_correct":true},{"text":"Inheriting from parent","is_correct":false},{"text":"Implementing interfaces","is_correct":false},{"text":"Method overriding","is_correct":false}]', 'Wrapping data and methods together', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which keyword is used to inherit a class?', 'mcq', '[{"text":"extends","is_correct":true},{"text":"implements","is_correct":false},{"text":"inherits","is_correct":false},{"text":"using","is_correct":false}]', 'extends', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is polymorphism?', 'mcq', '[{"text":"Object taking many forms","is_correct":true},{"text":"Hiding implementation","is_correct":false},{"text":"Single inheritance","is_correct":false},{"text":"Static binding","is_correct":false}]', 'Object taking many forms', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which data structure follows LIFO?', 'mcq', '[{"text":"Stack","is_correct":true},{"text":"Queue","is_correct":false},{"text":"LinkedList","is_correct":false},{"text":"ArrayList","is_correct":false}]', 'Stack', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is the default value of a boolean in Java?', 'mcq', '[{"text":"false","is_correct":true},{"text":"true","is_correct":false},{"text":"null","is_correct":false},{"text":"0","is_correct":false}]', 'false', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which loop is guaranteed to execute at least once?', 'mcq', '[{"text":"do-while","is_correct":true},{"text":"for","is_correct":false},{"text":"while","is_correct":false},{"text":"foreach","is_correct":false}]', 'do-while', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What does the super keyword do?', 'mcq', '[{"text":"Refers to parent class","is_correct":true},{"text":"Refers to current class","is_correct":false},{"text":"Creates superclass","is_correct":false},{"text":"Imports parent","is_correct":false}]', 'Refers to parent class', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which class is used to read input from the user?', 'mcq', '[{"text":"Scanner","is_correct":true},{"text":"Reader","is_correct":false},{"text":"Input","is_correct":false},{"text":"Console","is_correct":false}]', 'Scanner', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is an abstract class?', 'mcq', '[{"text":"A class that cannot be instantiated","is_correct":true},{"text":"A class with only static methods","is_correct":false},{"text":"A final class","is_correct":false},{"text":"An interface","is_correct":false}]', 'A class that cannot be instantiated', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which keyword is used for exception handling?', 'mcq', '[{"text":"try","is_correct":true},{"text":"handle","is_correct":false},{"text":"error","is_correct":false},{"text":"except","is_correct":false}]', 'try', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is the purpose of the finally block?', 'mcq', '[{"text":"Always executes after try-catch","is_correct":true},{"text":"Handles exceptions","is_correct":false},{"text":"Defines constants","is_correct":false},{"text":"Ends the program","is_correct":false}]', 'Always executes after try-catch', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which collection uses key-value pairs?', 'mcq', '[{"text":"HashMap","is_correct":true},{"text":"ArrayList","is_correct":false},{"text":"LinkedList","is_correct":false},{"text":"HashSet","is_correct":false}]', 'HashMap', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is a constructor?', 'mcq', '[{"text":"Special method called during object creation","is_correct":true},{"text":"A static method","is_correct":false},{"text":"A destructor","is_correct":false},{"text":"An interface method","is_correct":false}]', 'Special method called during object creation', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What does break do in a loop?', 'mcq', '[{"text":"Exits the loop","is_correct":true},{"text":"Skips to next iteration","is_correct":false},{"text":"Pauses execution","is_correct":false},{"text":"Restarts the loop","is_correct":false}]', 'Exits the loop', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which type of inheritance is not supported in Java (for classes)?', 'mcq', '[{"text":"Multiple","is_correct":true},{"text":"Single","is_correct":false},{"text":"Multilevel","is_correct":false},{"text":"Hierarchical","is_correct":false}]', 'Multiple', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is garbage collection?', 'mcq', '[{"text":"Automatic memory management","is_correct":true},{"text":"Deleting source files","is_correct":false},{"text":"Removing comments","is_correct":false},{"text":"Clearing the console","is_correct":false}]', 'Automatic memory management', 1),
