('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which keyword makes a variable constant?', 'mcq', '[{"text":"final","is_correct":true},{"text":"const","is_correct":false},{"text":"static","is_correct":false},{"text":"immutable","is_correct":false}]', 'final', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is an interface in Java?', 'mcq', '[{"text":"A contract with abstract methods","is_correct":true},{"text":"A concrete class","is_correct":false},{"text":"A data type","is_correct":false},{"text":"A package","is_correct":false}]', 'A contract with abstract methods', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'Which method converts a string to an integer?', 'mcq', '[{"text":"Integer.parseInt()","is_correct":true},{"text":"String.toInt()","is_correct":false},{"text":"Int.parse()","is_correct":false},{"text":"Convert.toInteger()","is_correct":false}]', 'Integer.parseInt()', 1),
('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What does the instanceof operator do?', 'mcq', '[{"text":"Checks if an object is of a specific type","is_correct":true},{"text":"Creates an instance","is_correct":false},{"text":"Compares values","is_correct":false},{"text":"Copies an object","is_correct":false}]', 'Checks if an object is of a specific type', 1),
