('14ca9458-008e-4ffb-a315-665de1719dec', 1, 'What is a thread in Java?', 'mcq', '[{"text":"A lightweight process","is_correct":true},{"text":"A heavy process","is_correct":false},{"text":"A memory block","is_correct":false},{"text":"A file stream","is_correct":false}]', 'A lightweight process', 1);
